// fastforward0002.js
import { rn2, rnd, d, rne, rnz } from "./rng.js";

function play(arr) {
    for (const c of arr) {
        if (c.f === 'rn2') rn2(c.b);
        else if (c.f === 'rnd') rnd(c.b);
        else if (c.f === 'rnz') rnz(c.b);
        else if (c.f === 'rne') rne(c.b);
        else if (c.f === 'd') d(c.a[0], c.a[1]);
    }
}

